import json
import base64
import pickle

def lambda_handler(event, context):
    # Load the message from API Gateway into a python dict.
    msg = base64.b64decode(event['awslogs']['data']) 
    
    # Deserialize the JSON data and load it into Python objects using pickle module.
    decoded_msg = pickle.loads(json.loads(msg))
  
    # You can then process your deserialized message as you wish.
    print(decoded_msg)